def canFinish(self, numCourses: int, prerequisites: List[List[int]]) -> bool:

    # Create a graph to represent the prerequisites
    graph = {}
    for prereq in prerequisites:
        node1 = prereq[0]
        node2 = prereq[1]
        if node1 in graph:
            graph[node1].append(node2)
        else:
            graph[node1] = [node2]

    # Check if a BFS can be performed on the graph
    courses_taken = set()
    for course in range(numCourses):
        if course not in courses_taken:
            courses_taken.add(course)
            if course in graph:
                for neighbor in graph[course]:
                if neighbor not in courses_taken:
                    return False
    return True

